def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 1:
            priorities[i] = np.inf
        elif ratio == 1:
            priorities[i] = 0
        else:
            score = 0
            temp_ratio = ratio
            for _ in range(5):
                if temp_ratio <= 0:
                    break
                score += -np.log(temp_ratio)
                temp_ratio *= 0.9
            if cap < item * 2:
                score *= 1.5
            if cap > item * 10:
                score *= 0.5
            priorities[i] = score
    return priorities
